// Compliant: Context-appropriate naming
func analyzeWebTraffic(requests []HTTPRequest) TrafficStats {
    var uniqueVisitors map[string]bool
    var totalPageViews int
    var averageResponseTime time.Duration
    var maxResponseTime time.Duration

    responseTimes := make([]time.Duration, 0, len(requests))

    for _, request := range requests {
        // Track unique visitors
        if uniqueVisitors == nil {
            uniqueVisitors = make(map[string]bool)
        }
        uniqueVisitors[request.ClientIP] = true

        // Count page views
        if request.IsPageView() {
            totalPageViews++
        }

        // Track response times
        responseTime := request.ResponseTime
        responseTimes = append(responseTimes, responseTime)

        if responseTime > maxResponseTime {
            maxResponseTime = responseTime
        }
    }

    // Calculate average
    var totalResponseTime time.Duration
    for _, rt := range responseTimes {
        totalResponseTime += rt
    }
    if len(responseTimes) > 0 {
        averageResponseTime = totalResponseTime / time.Duration(len(responseTimes))
    }

    return TrafficStats{
        UniqueVisitorCount:    len(uniqueVisitors),
        TotalPageViews:        totalPageViews,
        AverageResponseTime:   averageResponseTime,
        MaxResponseTime:       maxResponseTime,
    }
}

// Compliant: Receiver naming conventions
type UserRepository struct {
    db *sql.DB
}

// Use short receiver names (ur for UserRepository)
func (ur *UserRepository) FindByID(userID string) (*User, error) {
    var user User

    query := `SELECT id, name, email, created_at FROM users WHERE id = ?`
    err := ur.db.QueryRow(query, userID).Scan(
        &user.ID,
        &user.Name,
        &user.Email,
        &user.CreatedAt,
    )

    if err != nil {
        if errors.Is(err, sql.ErrNoRows) {
            return nil, ErrUserNotFound
        }
        return nil, fmt.Errorf("database query failed: %w", err)
    }

    return &user, nil
}

